auto group_and_reduce = [&] (const auto& vals, auto f, size_t num_buckets, auto identity) {
  using T = typename std::remove_reference_t<decltype(vals)>::value_type;
  auto keys = parlay::tabulate(vals.size(), [&](size_t i) { return f(vals[i]); });
  auto [offsets, sizes] = parlay::group_by_index(keys, num_buckets);

  auto vals_ptr = vals.data();

  return parlay::reduce_by_index(
      offsets, sizes, num_buckets, identity,
      [&](size_t i) { return vals_ptr[i]; },
      parlay::plus<T>());
};

