std::vector<std::vector<int>> group_by_key(const std::vector<std::pair<int, int>>& input) {
    using namespace parlay;

    if (input.empty()) return {};

    size_t n = input.size();
    auto keys = parlay::tabulate(n, [&](size_t i) { return input[i].first; });
    auto values = parlay::tabulate(n, [&](size_t i) { return input[i].second; });

    auto grouped = parlay::group_by_key(keys, values);

    std::vector<std::vector<int>> result(grouped.size());
    for (size_t i = 0; i < grouped.size(); ++i) {
        result[i] = std::vector<int>(grouped[i].size());
        parlay::parallel_for(0, grouped[i].size(), [&](size_t j) {
            result[i][j] = grouped[i][j];
        });
    }
    return result;
}

