    UncopyableThing(UncopyableThing&& other) noexcept : val(other.val) { other.val = -1; } // Move constructor
    UncopyableThing& operator=(UncopyableThing&& other) noexcept { // Move assignment
        if (this != &other) {
            val = other.val;
            other.val = -1; // Mark source as moved from
        }
        return *this;
