// Define ParlayLib conversion lambda
// NOTE: The test uses parlay::to_chars(ss.str()) which appears to convert a std::string
// into a format compatible with parlay::chars_to_long_double. This is a specific usage
// demonstrated in the test, potentially simplifying std::string to Parlay sequence conversion.
auto convert_parlay = [](long double x) {
  std::stringstream ss;
