// Fill the WorkerSpecific variable in parallel. Each worker writes its ID.
// The granularity of 1 makes it more likely different workers handle iterations,
// although Parlay's scheduler ultimately decides.
parlay::parallel_for(0, 1000, [&](size_t) {
  // Assign the current worker's ID to this worker's slot
  *list = static_cast<int>(parlay::worker_id());
}, 1);

// Demonstrate backward iteration from list.end()
// list.end() points one position past the last worker's slot.
// We iterate backward to access the slots for each worker.

// Method 1: Using iterator arithmetic (it - p)
auto it_arithmetic = list.end();
// Method 2: Using decrement (--)
auto it_decrement = list.end();

// Iterate backward from the last worker slot (end() - 1)
// down to the first worker slot (end() - num_workers()).
for (unsigned p = 1; p <= parlay::num_workers(); ++p) {
    // Calculate position using arithmetic subtraction
    auto position_arithmetic = it_arithmetic - p;

    // Calculate position using repeated decrements
    --it_decrement;

